 3→import {DiffItem} from './zhipuCompare';
 4→
 5→// 生成标红差异的 .docx 文件
 6→export async function generateDiffDocx(
 7→  originalFilePath: string,
 8→  diffs: DiffItem[],
 9→): Promise<string> {
10→  const base64 = await RNFS.readFile(originalFilePath, 'base64');
11→  const zip = await JSZip.loadAsync(base64, {base64: true});
12→  let docXml = (await zip.file('word/document.xml')?.async('string')) || '';
13→
14→  // 构建差异位置索引
15→  const diffByPosition = new Map<number, DiffItem[]>();
16→  for (const diff of diffs) {
17→    const pos = diff.position;
18→    if (!diffByPosition.has(pos)) {
19→      diffByPosition.set(pos, []);
20→    }
21→    diffByPosition.get(pos)!.push(diff);
22→  }
23→
24→  // 找到所有段落并在有差异的段落后插入红色标注
25→  const pRegex = /<w:p[\s>][\s\S]*?<\/w:p>/g;
26→  let paragraphIndex = 0;
27→  let offset = 0;
28→  let match;
29→  const insertions: {pos: number; text: string}[] = [];
30→
31→  // 先收集所有非空段落的位置
32→  const pMatches: {index: number; length: number; pIdx: number}[] = [];
33→  while ((match = pRegex.exec(docXml)) !== null) {
34→    const tRegex = /<w:t[^>]*>([\s\S]*?)<\/w:t>/g;
35→    let hasText = false;
36→    let t;
37→    while ((t = tRegex.exec(match[0])) !== null) {
38→      if (t[1].trim()) {hasText = true; break;}
39→    }
40→    if (hasText) {
41→      pMatches.push({index: match.index, length: match[0].length, pIdx: paragraphIndex});
42→      paragraphIndex++;
43→    }
44→  }
45→
46→  // 在有差异的段落后插入红色注释段落
47→  for (let i = pMatches.length - 1; i >= 0; i--) {
48→    const pm = pMatches[i];
49→    const itemDiffs = diffByPosition.get(pm.pIdx);
50→    if (!itemDiffs || itemDiffs.length === 0) continue;
51→
52→    for (const diff of itemDiffs) {
53→      let label = '';
54→      if (diff.type === 'mismatch') {
55→        label = `【差异】文档: "${diff.docText}" → 录音: "${diff.audioText}"`;
56→      } else if (diff.type === 'missing_in_audio') {
57→        label = `【录音缺失】"${diff.docText}"`;
58→      } else {
59→        label = `【录音多出】"${diff.audioText}"`;
60→      }
61→
62→      const redParagraph = `<w:p><w:pPr><w:rPr><w:color w:val="FF0000"/><w:b/></w:rPr></w:pPr><w:r><w:rPr><w:color w:val="FF0000"/><w:b/></w:rPr><w:t xml:space="preserve">${escapeXml(label)}</w:t></w:r></w:p>`;
63→
64→      const insertPos = pm.index + pm.length;
65→      docXml = docXml.slice(0, insertPos) + redParagraph + docXml.slice(insertPos);
66→    }
67→  }
68→
69→  zip.file('word/document.xml', docXml);
70→  const outputBase64 = await zip.generateAsync({type: 'base64'});
71→  const outputPath = `${RNFS.CachesDirectoryPath}/对比结果_${Date.now()}.docx`;
72→  await RNFS.writeFile(outputPath, outputBase64, 'base64');
73→  return outputPath;
74→}
75→
76→function escapeXml(str: string): string {
77→  return str
78→    .replace(/&/g, '&amp;')
79→    .replace(/</g, '&lt;')
80→    .replace(/>/g, '&gt;')
81→    .replace(/"/g, '&quot;')
82→    .replace(/'/g, '&apos;');
83→}
