 4→// 解析 .docx 文件提取纯文本（按段落）
 5→export async function parseDocx(filePath: string): Promise<string[]> {
 6→  const base64 = await RNFS.readFile(filePath, 'base64');
 7→  const zip = await JSZip.loadAsync(base64, {base64: true});
 8→  const docXml = await zip.file('word/document.xml')?.async('string');
 9→  if (!docXml) {
10→    throw new Error('无法读取Word文档内容');
11→  }
12→
13→  // 提取段落文本
14→  const paragraphs: string[] = [];
15→  const pRegex = /<w:p[\s>][\s\S]*?<\/w:p>/g;
16→  let pMatch;
17→  while ((pMatch = pRegex.exec(docXml)) !== null) {
18→    const pXml = pMatch[0];
19→    // 提取所有 <w:t> 标签内的文字
20→    const tRegex = /<w:t[^>]*>([\s\S]*?)<\/w:t>/g;
21→    let text = '';
22→    let tMatch;
23→    while ((tMatch = tRegex.exec(pXml)) !== null) {
24→      text += tMatch[1];
25→    }
26→    if (text.trim()) {
27→      paragraphs.push(text.trim());
28→    }
29→  }
30→
31→  return paragraphs;
32→}
